mapper.select:
SELECT o.*, u.name as user_name, h.name as handler_name, CASE WHEN e.id IS NOT NULL THEN 1 ELSE 0 END as has_evaluation FROM repair_order o LEFT JOIN user u ON o.user_id = u.id LEFT JOIN user h ON o.handler_id = h.id LEFT JOIN evaluation e ON o.id = e.order_id WHERE o.user_id = #{userId}
AND o.status = #{status}
ORDER BY o.create_time DESC

SELECT o.*, u.name as user_name, h.name as handler_name, CASE WHEN e.id IS NOT NULL THEN 1 ELSE 0 END as has_evaluation FROM repair_order o LEFT JOIN user u ON o.user_id = u.id LEFT JOIN user h ON o.handler_id = h.id LEFT JOIN evaluation e ON o.id = e.order_id
AND o.status = #{status}
AND o.building = #{building}
ORDER BY o.priority ASC, o.create_time DESC

mapper.update:
UPDATE repair_order
SET status = #{status}, handler_id = #{handlerId}, handle_time = NOW(), update_time = NOW()
WHERE id = #{id}

UPDATE repair_order
SET handle_note = #{note}, status = 2, finish_time = NOW(), update_time = NOW()
WHERE id = #{id}
